return ['domain'=>NULL,'plural-forms'=>'nplurals=2; plural=n != 1;','language'=>'de_DE','project-id-version'=>'JPKCom Simple Lang 1.0.0','pot-creation-date'=>'2025-12-17T11:57:24+00:00','po-revision-date'=>'2025-12-16 12:00+0100','x-generator'=>'Manual translation by JPKCom','messages'=>['JPKCom Simple Lang'=>'Simple Lang','Simple Lang Settings'=>'Simple Lang Einstellungen','Simple Lang'=>'Simple Lang','Post Type Settings'=>'Inhaltstyp-Einstellungen','Select which post types should have the frontend language selection dropdown in their edit screens.'=>'Wählen Sie aus, welche Inhaltstypen die Sprachauswahl in ihren Bearbeitungsansichten haben sollen.','Enable Language Selection'=>'Sprachauswahl aktivieren','No public post types found.'=>'Keine öffentlichen Inhaltstypen gefunden.','Posts and Pages are enabled by default. Unchecking a post type will hide the language selector on its edit screen and disable language override in the frontend.'=>'Beiträge und Seiten sind standardmäßig aktiviert. Wenn Sie einen Inhaltstyp deaktivieren, wird die Sprachauswahl ausgeblendet und die Sprachüberschreibung im Frontend deaktiviert.','Settings saved successfully.'=>'Einstellungen erfolgreich gespeichert.','Save Settings'=>'Einstellungen speichern','How to Add More Languages'=>'Weitere Sprachen hinzufügen','The language dropdown in the post editor only shows languages that are already installed on your WordPress site. To add more languages:'=>'Die Sprachauswahl im Beitragseditor zeigt nur Sprachen an, die bereits auf Ihrer WordPress-Website installiert sind. Um weitere Sprachen hinzuzufügen:','Go to Settings → General in your WordPress admin'=>'Gehen Sie zu Einstellungen → Allgemein in Ihrem WordPress-Adminbereich','Find the "Site Language" dropdown'=>'Suchen Sie das Dropdown-Menü "Sprache der Website"','Select the language you want to add (e.g., French, Spanish, Italian)'=>'Wählen Sie die Sprache aus, die Sie hinzufügen möchten (z.B. Französisch, Spanisch, Italienisch)','Click "Save Changes" - WordPress will automatically download the language pack'=>'Klicken Sie auf "Änderungen speichern" - WordPress lädt das Sprachpaket automatisch herunter','Optional: Change the site language back to your preferred default language'=>'Optional: Ändern Sie die Website-Sprache zurück zu Ihrer bevorzugten Standardsprache','The new language will now appear in the post editor dropdown!'=>'Die neue Sprache erscheint nun in der Sprachauswahl des Beitragseditors!','Quick Access:'=>'Schnellzugriff:','Go to General Settings'=>'Zu den Allgemeinen Einstellungen','WordPress supports over 200 languages. View the full list at %s'=>'WordPress unterstützt über 200 Sprachen. Die vollständige Liste finden Sie unter %s','Download failed: %s'=>'Download fehlgeschlagen: %s','Security verification failed: Plugin checksum mismatch. Expected: %s, Got: %s'=>'Sicherheitsüberprüfung fehlgeschlagen: Plugin-Prüfsumme stimmt nicht überein. Erwartet: %s, Erhalten: %s','Default (Site Language)'=>'Standard (Website-Sprache)','Translation Links'=>'Übersetzungsverknüpfungen','No other posts available for translation linking.'=>'Keine weiteren Beiträge für Übersetzungsverknüpfungen verfügbar.','Select translations:'=>'Übersetzungen auswählen:','Hold Ctrl (Cmd on Mac) to select multiple translations. Posts are grouped by language. Only published translations will appear in hreflang tags.'=>'Halten Sie Strg (Cmd auf Mac), um mehrere Übersetzungen auszuwählen. Beiträge sind nach Sprache gruppiert. Nur veröffentlichte Übersetzungen erscheinen in den hreflang-Tags.','%d translation linked'=>'%d Übersetzung verknüpft' . "\0" . '%d Übersetzungen verknüpft','Frontend Language Select'=>'Frontend-Sprachauswahl','Select the language for this page:'=>'Wählen Sie die Sprache für diese Seite:','This will override the site language for this specific page in the frontend. Leave as "Default" to use the site-wide language setting.'=>'Dies überschreibt die Website-Sprache für diese spezifische Seite im Frontend. Lassen Sie "Standard" ausgewählt, um die globale Spracheinstellung zu verwenden.','Post Language Is'=>'Seitensprache ist','Simple Lang: Check if post has a specific language'=>'Simple Lang: Prüfen, ob Seite eine bestimmte Sprache hat','Post Has Custom Language'=>'Seite hat benutzerdefinierte Sprache','Simple Lang: Check if post has any custom language set'=>'Simple Lang: Prüfen, ob Seite eine benutzerdefinierte Sprache hat','Post Uses Default Language'=>'Seite verwendet Standardsprache','Simple Lang: Check if post uses the site default language'=>'Simple Lang: Prüfen, ob Seite die Website-Standardsprache verwendet']];